import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { Lesson } from '../../core/models';

@Component({
  selector: 'app-lesson',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './lesson.component.html',
  styleUrl: './lesson.component.css',
})
export class LessonComponent implements OnInit {
  loading = signal(false);
  error = signal<string | null>(null);
  marked = signal(false);

  lesson = signal<Lesson | null>({
    id: 'l1',
    moduleId: 'm1',
    order: 1,
    title: 'What is HTML?',
    content:
      '<p>HTML (HyperText Markup Language) is the standard markup language for documents ' +
      'designed to be displayed in a web browser. It defines the <strong>structure</strong> ' +
      'of a page using elements.</p>' +
      '<h3>Key ideas</h3>' +
      '<ul>' +
      '<li>Elements are written with <em>tags</em> like &lt;p&gt; and &lt;h1&gt;.</li>' +
      '<li>Tags usually come in pairs: an opening and a closing tag.</li>' +
      '<li>The browser reads HTML and renders it into the page you see.</li>' +
      '</ul>' +
      '<p>In the next lesson we will look at how a full page is structured from head to body.</p>',
    completed: false,
  });

  courseId = 'c1';

  ngOnInit(): void {
    // On load the student "views" this lesson, marking it complete.
    // service_agent wires this to api.markLessonViewed(id).
    this.marked.set(true);
  }
}
